// frontend/src/pages/CreatePostPage.js

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const CreatePostPage = () => {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [image, setImage] = useState(null);
  const [error, setError] = useState('');

  const [titleFocus, setTitleFocus] = useState(false);
  const [bodyFocus, setBodyFocus] = useState(false);
  const [btnHover, setBtnHover] = useState(false);
  const [btnActive, setBtnActive] = useState(false);

  // 👇 re-render on theme change
  const [themeTrigger, setThemeTrigger] = useState(false);

  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    const handleThemeChange = () => {
      setThemeTrigger(prev => !prev);
    };
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const isDark = document.body.classList.contains("dark-mode");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);

    try {
      const { data } = await API.post('/posts', fd);
      navigate(`/posts/${data._id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to publish post');
    }
  };

  const styles = {
    page: {
      minHeight: '90vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      padding: '20px',
      backgroundColor: isDark ? '#560032' : '#FAE8ED',
      fontFamily: 'Georgia, serif',
      color: isDark ? '#f5d6e6' : 'rgb(12, 75, 52)'
    },

    container: {
      width: '100%',
      maxWidth: '700px',
      padding: '30px',
      borderRadius: '20px',
      backgroundColor: isDark ? '#2e091e' : '#f7c6d9',
      boxShadow: isDark
        ? '0 10px 30px rgba(34, 33, 33, 0.6)'
        : '0 10px 30px rgba(0,0,0,0.1)'
    },

    heading: {
      textAlign: 'center',
      marginBottom: '20px'
      
    },

    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '18px'
    },

    input: {
      padding: '14px 18px',
      borderRadius: '15px',
      border: '2px solid transparent',
      fontSize: '15px',
      outline: 'none',
      transition: '0.3s',
      backgroundColor: isDark ? '#442c44' : '#FAE8ED',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)'
    },

    inputFocus: {
      backgroundColor: isDark ? '#4a2e4a' : '#ffffff',
      borderColor: isDark ? '#ff7aa2' : 'rgb(12, 75, 52)',
      boxShadow: isDark
        ? '0 5px 15px rgba(255,122,162,0.2)'
        : '0 5px 15px rgba(12,75,52,0.1)'
    },

    textarea: {
      padding: '14px 18px',
      borderRadius: '15px',
      border: '2px solid transparent',
      fontSize: '15px',
      outline: 'none',
      resize: 'none',
      transition: '0.3s',
      backgroundColor: isDark ? '#3a253a' : '#FAE8ED',
      color: isDark ? '#fff' : 'rgb(12, 75, 52)'
    },

    fileInput: {
      color: isDark ? '#fff' : 'rgb(12, 75, 52)'
    },

    button: {
      padding: '14px',
      borderRadius: '30px',
      border: 'none',
      fontWeight: 'bold',
      cursor: 'pointer',
      backgroundColor: isDark ? '#f8b5cf' : 'rgb(12, 75, 52)',
      color: '#073210',
      transition: '0.3s'
    },

    buttonHover: {
      backgroundColor: '#ff7aa2',
      transform: 'scale(1.05)'
    },

    buttonActive: {
      transform: 'scale(0.97)'
    },

    error: {
      color: '#ff4d4d',
      textAlign: 'center',
      fontSize: '0.9rem'
    }
  };

  const getButtonStyle = () => {
    if (btnActive) return { ...styles.button, ...styles.buttonActive };
    if (btnHover) return { ...styles.button, ...styles.buttonHover };
    return styles.button;
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Write a New Post</h2>

        {error && <p style={styles.error}>{error}</p>}

        <form style={styles.form} onSubmit={handleSubmit}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Post title"
            required
            style={
              titleFocus
                ? { ...styles.input, ...styles.inputFocus }
                : styles.input
            }
            onFocus={() => setTitleFocus(true)}
            onBlur={() => setTitleFocus(false)}
          />

          <textarea
            value={body}
            onChange={(e) => setBody(e.target.value)}
            placeholder="Write your post here..."
            rows={12}
            required
            style={
              bodyFocus
                ? { ...styles.textarea, ...styles.inputFocus }
                : styles.textarea
            }
            onFocus={() => setBodyFocus(true)}
            onBlur={() => setBodyFocus(false)}
          />

          {user?.role === 'admin' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                <label>Upload Cover Image (Admin only):</label>

                {/* Hidden file input */}
                <input
                  type="file"
                  accept="image/*"
                  id="fileUpload"
                  style={{ display: 'none' }}
                  onChange={(e) => setImage(e.target.files[0])}
                />

                {/* Custom button */}
                <label
                  htmlFor="fileUpload"
                  style={{
                    padding: '12px',
                    borderRadius: '20px',
                    cursor: 'pointer',
                    textAlign: 'center',
                    fontWeight: 'bold',
                    backgroundColor: isDark ? '#3a253a' : '#FAE8ED',
                    color: isDark ? '#fff' : 'rgb(12, 75, 52)',
                    border: `2px dashed ${isDark ? '#ff7aa2' : 'rgb(12, 75, 52)'}`,
                    transition: '0.3s'
                  }}
                >
                  {image ? `📸 ${image.name}` : 'Choose Image'}
                </label>
              </div>
            )}
          <button
            type="submit"
            style={getButtonStyle()}
            onMouseEnter={() => setBtnHover(true)}
            onMouseLeave={() => setBtnHover(false)}
            onMouseDown={() => setBtnActive(true)}
            onMouseUp={() => setBtnActive(false)}
          >
            Publish Post
          </button>
        </form>
      </div>
    </div>
  );
};

export default CreatePostPage;
